  const p = tabs[idx];
  const txt = await p.locator('main').innerText().catch(e=>'');
  const title = await p.title().catch(e=>'ERR');
  const score = (txt.match(/Scored\s*([0-9.]+)\s*Rated\s*([^\n]+)/)||[]).slice(1,3).join(' ');
  const priceMatches = [...txt.matchAll(/Price\s*\$([0-9,]+)/g)].map(m=>m[1]);
  console.log(idx+' | '+title+' | score '+score+' | prices '+priceMatches.slice(0,5).join(', '));
}")

